// Extract top 10 headlines into a single text block for the AI prompt
const articles = $input.first().json.articles || [];

const top10 = articles.slice(0, 10).map(a => ({
  title: a.title || '',
  description: a.description || '',
  source: a.source?.name || '',
  url: a.url || ''
}));

const headlineText = top10
  .map((a, i) => `${i + 1}. ${a.title}\n   ${a.description}\n   Source: ${a.source}`)
  .join('\n\n');

return [{
  json: {
    headlines: headlineText,
    articleCount: top10.length,
    articles: top10
  }
}];

