// Parse AI output and build Supabase payload
const rawText = $input.first().json.message?.content || $input.first().json.text || $input.first().json.output || '';

let aiOutput;
try {
  aiOutput = typeof rawText === 'string' ? JSON.parse(rawText) : rawText;
} catch (e) {
  throw new Error(`Failed to parse AI output as JSON: ${e.message}\n\nRaw output: ${rawText.substring(0, 500)}`);
}

// Validate required fields
if (!aiOutput.title || !aiOutput.slug || !aiOutput.blocks || !Array.isArray(aiOutput.blocks)) {
  throw new Error(`AI output missing required fields. Got keys: ${Object.keys(aiOutput).join(', ')}`);
}

// Validate blocks have required structure
const validTypes = ['paragraph', 'heading', 'blockquote', 'bullet-list', 'ordered-list', 'code', 'image', 'divider', 'table', 'callout', 'quiz', 'chart', 'formula'];
for (const block of aiOutput.blocks) {
  if (!block.id || !block.type) {
    throw new Error(`Block missing id or type: ${JSON.stringify(block)}`);
  }
  if (!validTypes.includes(block.type)) {
    throw new Error(`Invalid block type: ${block.type}`);
  }
}

// Helper: count words in blocks
function countWords(blocks) {
  let count = 0;
  for (const block of blocks) {
    if (block.type === 'paragraph' || block.type === 'blockquote' || block.type === 'callout') {
      count += (block.content || '').split(/\s+/).filter(Boolean).length;
    } else if (block.type === 'heading') {
      count += (block.text || '').split(/\s+/).filter(Boolean).length;
    } else if (block.type === 'bullet-list' || block.type === 'ordered-list') {
      for (const item of block.items || []) {
        count += item.split(/\s+/).filter(Boolean).length;
      }
    } else if (block.type === 'table') {
      for (const row of block.rows || []) {
        for (const cell of row) {
          count += String(cell).split(/\s+/).filter(Boolean).length;
        }
      }
    }
  }
  return count;
}

// Fix multiple-choice/chart questions with options crammed into a single string
if (aiOutput.quiz && aiOutput.quiz.questions) {
  for (const q of aiOutput.quiz.questions) {
    if ((q.type === 'multiple-choice' || q.type === 'chart') && Array.isArray(q.options)) {
      if (q.options.length === 1 && q.options[0].includes(',')) {
        q.options = q.options[0].split(',').map(s => s.trim()).filter(Boolean);
        q.correctIndex = 0;
      }
    }
  }
}

// Validate categories
const validCategories = ['trading', 'economics', 'finance', 'business', 'banking-insurance', 'education'];
const categories = (aiOutput.categories || ['finance']).filter(c => validCategories.includes(c));
if (categories.length === 0) categories.push('finance');

const postPayload = {
  slug: aiOutput.slug,
  title: aiOutput.title,
  description: (aiOutput.description || '').substring(0, 160) || null,
  categories: categories,
  tags: aiOutput.tags || [],
  featured: false,
  draft: true,
  cover_url: null,
  cover_alt: null,
  affiliate_disclosure: false,
  author_name: 'Econopedia AI',
  author_slug: 'econopedia-ai',
  lead_magnet: null,
  blocks: aiOutput.blocks,
  word_count: countWords(aiOutput.blocks),
};

return [{
  json: {
    post: postPayload,
    quiz: aiOutput.quiz || null,
    includeQuiz: aiOutput.include_quiz === true,
  }
}];

// Get the quiz ID returned by the Insert Quiz node
const quizRecord = $input.first().json;
const quizId = quizRecord.id;

// Get the original post payload from Validate & Build Payload
const post = $('Validate & Build Payload').item.json.post;

// Append quiz block to the end of the blocks array
const blocksWithQuiz = [
  ...post.blocks,
  { id: 'quiz-block', type: 'quiz', quizId: quizId }
];

// Return the complete post payload with quiz block included
return [{
  json: {
    slug: post.slug,
    title: post.title,
    description: post.description,
    categories: post.categories,
    tags: post.tags,
    featured: post.featured,
    draft: post.draft,
    cover_url: post.cover_url,
    cover_alt: post.cover_alt,
    affiliate_disclosure: post.affiliate_disclosure,
    author_name: post.author_name,
    author_slug: post.author_slug,
    lead_magnet: post.lead_magnet,
    blocks: blocksWithQuiz,
    word_count: post.word_count,
  }
}];

// Save headlines to workflow static data so the merge node can retrieve them
// without relying on a node name reference
const staticData = $getWorkflowStaticData('global');
const input = $input.first().json;
staticData.headlines = input.headlines || '';
staticData.articles = JSON.stringify(input.articles || []);
staticData.articleCount = input.articleCount || 0;

return $input.all();

// Retrieve headlines from workflow static data (stashed earlier)
const staticData = $getWorkflowStaticData('global');
const headlines = staticData.headlines || '';
let articles = [];
try { articles = JSON.parse(staticData.articles || '[]'); } catch(e) { articles = []; }
const articleCount = staticData.articleCount || 0;

// Collect recent post titles from Supabase node output
const recentItems = $input.all() || [];
const recentTitles = recentItems
  .map(item => item.json?.title)
  .filter(Boolean);

const recentList = recentTitles.length > 0
  ? recentTitles.map((t, i) => `${i + 1}. ${t}`).join('\n')
  : '(none)';

return [{
  json: {
    headlines,
    articles,
    articleCount,
    recentPostsList: recentList
  }
}];

// Parse the AI's topic pick
const rawText = $input.first().json.message?.content || $input.first().json.text || $input.first().json.output || '';
let pick;
try {
  pick = typeof rawText === 'string' ? JSON.parse(rawText) : rawText;
} catch (e) {
  pick = { index: 0, title: '', url: '', reason: '' };
}

// Get the original articles list from Fetch Recent Posts
const articles = $('Merge Context').item.json.articles || [];
const headlines = $('Merge Context').item.json.headlines || '';

// Try to get URL from the pick, or fall back to first article
const targetUrl = pick.url || (articles[pick.index || 0] || {}).url || '';
const targetTitle = pick.title || (articles[pick.index || 0] || {}).title || '';

return [{
  json: {
    pickedTopic: targetTitle,
    pickedReason: pick.reason || '',
    articleUrl: targetUrl,
    headlines: headlines,
    articles: articles
  }
}];

// Extract readable text from HTML
const html = $input.first().json.data || $input.first().json.body || '';
const topicInfo = $('Extract Topic URL').item.json;

// Strip HTML tags and extract text content
let text = typeof html === 'string' ? html : JSON.stringify(html);
text = text
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&[a-zA-Z]+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Limit to ~4000 chars to stay within token budget
const articleText = text.substring(0, 4000);

return [{
  json: {
    pickedTopic: topicInfo.pickedTopic,
    pickedReason: topicInfo.pickedReason,
    articleContent: articleText.length > 100 ? articleText : '(Could not fetch article content — write based on headline and your knowledge)',
    headlines: topicInfo.headlines
  }
}];
